<template>
         <div class="my-popups">
            <loader :is-visible="isLoading" />

            <div class="modal d-block">
                <div class="modal-dialog modal-dialog-centered modal-lg">
                    <div class="modal-content">

                        <div class="modal-header theme-primary partition-full d-flex justify-content-between align-items-center">
                            <h5 class="modal-title">{{ $t('Select')  }}</h5>
                            <span class="user-guide">
                                <a class="ancuserguide text-white" data-toggle="collapse" href="javascript:;"
                                    role="button" aria-expanded="false" aria-controls="collapseExample"> <em
                                        class="fa fa-files-o pr-2"></em>{{ $t('GuideForUser') }}</a>
                                <div id="collapseReplyUG" class="divancuserguide collapse overflow-auto">
                                    <div id="scrollbarreplyuserguideMangeView" class="custom-scrollbar-js">
                                        <div class="con" v-html="getUserGuideTitle()"></div>
                                    </div>
                                </div>
                            </span>
                            <button type="button" class="close" @click="Close">
                                <em class="fa fa-times"></em>
                            </button>
                        </div>

                        <div class="modal-body">
                       <dynamic-form lang="en" ref="validateSubsidy" :buttons="buttons" :schema="FormSchema"  v-on:OnSubmit="onSubmit" :mandatorytext="$t('MandatoryString')" >
                        <template v-slot:tgslot-ContractName="{ data }">
                          <div id="app">
                                    <SearchableSelect
                                        v-model="selectedClient"
                                        :items="clientList"
                                        :max-visible-chips="3"
                                        :action-buttons="{ selectAll: true, active: true, inactive: true, clear: true }"
                                        :item-fields="['text']"
                                        :group-fields="['groupText']"
                                        :max-render-items="50"
                                        :lazy-load="true"
                                        placeholder="Select Contract..."
                                        :min-search-length="0"
                                          :onChange="onClientChange"
                                        style="min-width: 300px"
                                        />
                    </div>
                </template>
                       </dynamic-form>
                       </div>
                   </div>
                </div>
             </div>
          </div>
    </template>
<script>
import DataService from '../../services/DataService';
import { locateBillingService } from '../../services/locateBillingService';
import SearchableSelect from '../Common/SearchableSelect.vue';
export default {
    components:{SearchableSelect},
props:{
    SetupId:{
        type:Number
    },
    FieldName:{
        type:String
    }
},
      data(){
        return{
            isLoading:false,
            selectedClient:'',
            filedData:[],
            FormSchema: [{
                    layoutType: "double",
                    Data: [ {
                    astype: "SelectField",
                    label: this.$t('fieldName'),
                    name: "FieldName",
                    value: "",
                    visibility: true,
                    placeholder: "",
                    disabled: false,
                    config: {
                        options: [],
                    },
                    validationRules: {
                        "required": true
                    },
                },{
                    astype: "SlotField",
                    label: this.$t('CONTRACT_NAME'),
                    name: "ContractName",
                    value: "",
                    visibility: true,
                    placeholder: "ContractName",
                    disabled: false,
                    config: {
                        options: [],
                    },
                    validationRules: {
                        "required": true
                    },
                },{
                    astype: "SelectField",
                    label: this.$t('UtilityName'),
                    name: "UtilityName",
                    value: "",
                    visibility: true,
                    placeholder: "UtilityName",
                    disabled: false,
                    config: {
                        options: [],
                        onChange: this.onSelectionUtilityChange
                    },
                    validationRules: {
                        "required": true
                    },
                },
                {
                    astype: "SelectField",
                    label: this.$t('SBA Id'),
                    name: "SBAId",
                    value: "",
                    visibility: true,
                    placeholder: "SBA Id",
                    disabled: false,
                    config: {
                        options: [],
                    },
                    validationRules: {
                        "required": true
                    },
                }]
                }],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>" + this.$t('Save')
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>" + this.$t('Cancel'),
                    onClick: this.Close,
                },
            ],
            clientList:[],
            FieldOptions: [],
            billingRuleOptions:[],
            returnSelectedSabData:[]
        }
      },
      created: async function () {
       await this.GetDDLCompanyContractClients();
       await this.GetFileds();
       setTimeout(() => {
    const groupedByService = {};
    this.clientList.forEach(item => {
        const groupText = item.groupText;
        if (!groupedByService[groupText]) {
            groupedByService[groupText] = {
                groupText: groupText,
                items: [],  
            };
        }
        groupedByService[groupText].items.push(item);
    });
    this.clientList = Object.keys(groupedByService).map((groupText) => {
        const group = groupedByService[groupText];
        return {
            groupText: group.groupText,
            items: group.items,
        };
    });

}, 500);

      },
      methods:{
      async  GetFileds(){
           var vm=this;
           vm.isLoading = true;
          // var url=`setupId=${vm.SetupId}&reqFrom=flag&isComeboCharges=&isTemplateColumnShow=`
           var url = `setupId=${vm.SetupId}&reqFrom=clientflag`;
          const response=  await locateBillingService.GetFieldsListBySetupId(url);
          if(response.data != '' && response.data.length > 0)
          {
            vm.FieldOptions=response.data;
            const optionsArray = response.data.map(element => ({
                name:element.DISPLAY_NAME,
                value:element.TEMPLATE_ID,
                columnName: element.COLUMN_NAME
                  }));
                  debugger
                  vm.$refs.validateSubsidy.updateProperty("FieldName", "config.options", optionsArray);
                const selectedOption = optionsArray.find(element => 
                element.columnName.toLowerCase() === vm.FieldName.toLowerCase());
                vm.$refs.validateSubsidy.updateProperty("FieldName", "value", selectedOption.value);
                vm.$refs.validateSubsidy.UpdateKeyValue();
                vm.isLoading = false;
          }
          else
          {
                 vm.isLoading = false;
                vm.FieldNameList = []; 
                vm.$refs.validateSubsidy.updateProperty("FieldName", "config.options", FieldNameList);
                 vm.$refs.validateSubsidy.updateProperty("FieldName", "value", "");
                vm.$refs.validateSubsidy.UpdateKeyValue(); 
          }
        },
        async GetDDLCompanyContractClients() {
            var vm = this;
            var url = `reqFrom=CUSTOM`;
            vm.isLoading = true;
            try {
                const response = await locateBillingService.getClientList(url);
                vm.clientList =  response.data.items;
                vm.isLoading = false;
            } catch (error) {
                vm.clientList = [];
                vm.isLoading = false;
            } finally {
                vm.isLoading = false;
            }
        },
        onClientChange(value,x) {
            var vm = this;
            vm.isLoading = true;
            var url = `clientId=${vm.selectedClient}&configId=&reqFrom=&clientIds=`;
            locateBillingService.getUtilityList(url).then(response => {
                vm.isLoading = false;
                  let UtilityList=[];
                  if (response.data) {
                    var json = response.data;
                    if (json != null) {
                        json.forEach(item => {
                            let obj = {
                                name: item.UTILITY_NAME,
                                value: item.UTILITY_ID
                            };
                            UtilityList.push(obj);
                        });
                        vm.$refs.validateSubsidy.updateProperty("UtilityName", "config.options", UtilityList);
                        vm.$refs.validateSubsidy.UpdateKeyValue();
                         vm.UtilityId = vm.$refs.validateSubsidy.getPropertyValue("UtilityId", "value");
                        vm.GetSbaIdListByUtilityId();
                    }
                }
            }).catch(error => {
                vm.isLoading = false;
                vm.UtilityList = []; 
                vm.$refs.validateSubsidy.updateProperty("UtilityName", "config.options", UtilityList);
                 vm.$refs.validateSubsidy.updateProperty("UtilityName", "value", "");
                vm.$refs.validateSubsidy.UpdateKeyValue();
            }).finally(() => {
                vm.isLoading = false;
            });
        },
        onSelectionUtilityChange(value,x) {
            var vm = this;
            vm.UtilityId = x.value;
            vm.GetSbaIdListByUtilityId();
        },
        GetSbaIdListByUtilityId: function () {
            var vm = this;
            vm.isLoading = true;
            let selctedValue = [];
            vm.SbaOptions=[]
            var url = `UtilityId=${vm.UtilityId}`;
            locateBillingService.GetSbaIdListByUtilityId(url).then(response => {
                if (response.data) {
                    var json = response.data;
                    vm.returnSelectedSabData=response.data;
                    if (json != null) {
                        json.forEach(item => {
                            let obj = {
                                name: item.NAME,
                                value: item.SBA_ID
                            };
                            selctedValue.push(obj);
                        });
                        vm.$refs.validateSubsidy.updateProperty("SBAId", "config.options", selctedValue);
                        vm.SbaOptions=selctedValue;
                        vm.$refs.validateSubsidy.UpdateKeyValue();
                        vm.isLoading = false;
                    }
                }
            }).catch((error)=>{
                vm.isLoading = false;
            }).finally(()=>{
                vm.isLoading = false;
            })
        },
        onSubmit(formfields, val){
            debugger
            var vm = this;
            var beSbaId = 0;
            var value = "";
            var SelectedValue="";
            var SBASelectedValue="";
            let filtered = vm.FieldOptions.filter(x => x.TEMPLATE_ID === formfields.FieldName);
            SelectedValue= filtered[0].COLUMN_NAME;
            if(formfields.SBAId){
                let filtered = vm.SbaOptions.filter(x => x.value === formfields.SBAId);
                SBASelectedValue= filtered[0].name;
            }
            if (SelectedValue == "SBA_ID"|| SelectedValue == "sba_id") {
                beSbaId = formfields.SBAId;
                value = SBASelectedValue;
            }
            var filedNameValue=vm.FormSchema[0].Data[0].value;
            var contractFieldValue=vm.selectedClient;
            var utilityFiledValue=vm.FormSchema[0].Data[2].value;
            var sabFiledValue=vm.FormSchema[0].Data[3].value;
            debugger
            var postJSON = {
                value: value,
                fieldName: SelectedValue,
                lineIds: utilityFiledValue,
                reqFrom: 'clientflag',
                setClient: 0,
                beSbaId: beSbaId,
                Comment: ''
            };
            const selectedElement = vm.returnSelectedSabData.find(element => element.SBA_ID === sabFiledValue);
            vm.$emit('CallBackFunction',selectedElement);
            // locateBillingService.SaveColumnItems(postJSON).then(async function (response) {
            //     if (response.data.msg == 'Success') {
            //         vm.ShowAlert(vm.$t('RecordUpdatedSuccessfully'), "success", true, vm.$t("Alert"));
            //         if(vm.reqFrom == "unprocessed"){
            //             await vm.$parent.FetchUnprocessedRecords();
            //         }else{
            //             setTimeout(async () => {
            //               await vm.$parent.FetchFlagRecords();
            //             }, 1000);
                
            //         }
            //         vm.Close();
            //     } else {
            //           vm.ShowAlert(vm.$t("ErrorWhileProcessingRequest"), "failure", true, vm.$t("Alert"));
            //     }

            // });
        },
        getUserGuideTitle() {
            let text = this.$t('User_Guide_Invoice_Change_File_Value');
            return text
                .replace(/\\n/g, '')
                .replace(/\\t/g, '&nbsp;');
        },

        Close() {
            this.$parent.isSabModel=false;
        },
      }

};
</script>